mapper.select:
/* SQL ID : MsgTmpltDAO.selectTmpltCnt 설 명 : 템플릿 목록 건수 조회 */ SELECT COUNT(*) FROM TB_LMS_MSG_TMPLT WHERE 1 = 1
AND ORG_ID = #{orgId}
AND MSG_CTS_GBNCD = #{msgCtsGbncd}
AND RGTR_ID = #{rgtrId}
AND MSG_TMPLT_TTL LIKE '%' || #{searchText} || '%'
AND MSG_TMPLT_CTS LIKE '%' || #{searchText} || '%'
AND (MSG_TMPLT_TTL LIKE '%' || #{searchText} || '%' OR MSG_TMPLT_CTS LIKE '%' || #{searchText} || '%')

/* SQL ID : MsgTmpltDAO.selectTmpltList 설 명 : 템플릿 목록 조회 */ SELECT * FROM ( SELECT ROWNUM AS RNUM, A.* FROM ( SELECT MSG_TMPLT_ID , ORG_ID , MSG_CTS_GBNCD , MSG_TMPLT_TTL , MSG_TMPLT_CTS , RGTR_ID , REG_DTTM , MDFR_ID , MOD_DTTM FROM TB_LMS_MSG_TMPLT WHERE 1 = 1
AND ORG_ID = #{orgId}
AND MSG_CTS_GBNCD = #{msgCtsGbncd}
AND RGTR_ID = #{rgtrId}
AND MSG_TMPLT_TTL LIKE '%' || #{searchText} || '%'
AND MSG_TMPLT_CTS LIKE '%' || #{searchText} || '%'
AND (MSG_TMPLT_TTL LIKE '%' || #{searchText} || '%' OR MSG_TMPLT_CTS LIKE '%' || #{searchText} || '%')
ORDER BY REG_DTTM DESC ) A WHERE ROWNUM <= #{lastIndex} ) WHERE RNUM >= #{firstIndex}

mapper.insert:
/*
     SQL ID : MsgTmpltDAO.registTmplt
     설  명 : 템플릿 등록
 */
INSERT INTO TB_LMS_MSG_TMPLT (
                               MSG_TMPLT_ID
                             , ORG_ID
                             , MSG_CTS_GBNCD
                             , MSG_TMPLT_TTL
                             , MSG_TMPLT_CTS
                             , RGTR_ID
                             , REG_DTTM
) VALUES (
           #{msgTmpltId}
         , #{orgId}
         , #{msgCtsGbncd}
         , #{msgTmpltTtl}
         , #{msgTmpltCts}
         , #{rgtrId}
         , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
         )

mapper.update:
/*
     SQL ID : MsgTmpltDAO.modifyTmplt
     설  명 : 템플릿 수정
 */
UPDATE TB_LMS_MSG_TMPLT
SET MSG_TMPLT_TTL = #{msgTmpltTtl}
, MSG_TMPLT_CTS = #{msgTmpltCts}
, MDFR_ID = #{mdfrId}
, MOD_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')

    , MSG_CTS_GBNCD = #{msgCtsGbncd}

WHERE MSG_TMPLT_ID = #{msgTmpltId}

mapper.delete:
/*
     SQL ID : MsgTmpltDAO.deleteTmplt
     설  명 : 템플릿 삭제
 */
DELETE FROM TB_LMS_MSG_TMPLT
WHERE MSG_TMPLT_ID = #{msgTmpltId}

/*
     SQL ID : MsgTmpltDAO.deleteAllTmplt
     설  명 : 템플릿 전체 삭제
 */
DELETE FROM TB_LMS_MSG_TMPLT
WHERE ORG_ID = #{orgId}

  AND MSG_CTS_GBNCD = #{msgCtsGbncd}


  AND RGTR_ID = #{rgtrId}

